import UIKit
import Foundation
import Alamofire
import SwiftyJSON

// Constants
let API_KEY = "YOUR_API_KEY"
let BASE_URL = "https://api.example.com"

// User Defaults for storing user data
let USER_DEFAULTS = UserDefaults.standard

// Portfolio class to manage user's portfolio
class Portfolio {
    var stocks: [String: Double] = [:]
    
    func addStock(stock: String, quantity: Int) {
        if let currentQuantity = stocks[stock] {
            stocks[stock] = currentQuantity + Double(quantity)
        } else {
            stocks[stock] = Double(quantity)
        }
    }
    
    func removeStock(stock: String, quantity: Int) {
        if let currentQuantity = stocks[stock] {
            if currentQuantity - Double(quantity) >= 0 {
                stocks[stock] = currentQuantity - Double(quantity)
            } else {
                print("Insufficient stock quantity")
            }
        } else {
            print("Stock not found in portfolio")
        }
    }
}

// Trade class to handle trade execution
class Trade {
    var stock: String
    var quantity: Int
    
    init(stock: String, quantity: Int) {
        self.stock = stock
        self.quantity = quantity
    }
    
    func executeTrade() {
        // API call to execute trade
        let parameters: [String: Any] = ["api_key": API_KEY, "stock": stock, "quantity": quantity]
        
        AF.request(BASE_URL + "/trade", method: .post, parameters: parameters)
            .responseJSON { response in
                if let json = try? JSON(data: response.data) {
                    print("Trade executed successfully")
                } else {
                    print("Error executing trade")
                }
        }
    }
}

// API class to handle secure API communication
class API {
    func getStockPrice(stock: String, completion: @escaping (Double?) -> Void) {
        let parameters: [String: Any] = ["api_key": API_KEY, "stock": stock]
        
        AF.request(BASE_URL + "/price", method: .get, parameters: parameters)
            .responseJSON { response in
                if let json = try? JSON(data: response.data) {
                    completion(json["price"].double)
                } else {
                    completion(nil)
                }
        }
    }
}

