// ViewController to handle user input and display portfolio information
class ViewController: UIViewController {
    @IBOutlet weak var stockTextField: UITextField!
    @IBOutlet weak var quantityTextField: UITextField!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        // Load user data from User Defaults
        if let stocks = USER_DEFAULTS.object(forKey: "stocks") as? [String: Double] {
            portfolio.stocks = stocks
        }
    }
    
    @IBAction func buyButtonTapped(_ sender: UIButton) {
        guard let stock = stockTextField.text, !stock.isEmpty else { return }
        guard let quantity = Int(quantityTextField.text ?? "") else { return }
        
        // Execute trade and update portfolio
        let trade = Trade(stock: stock, quantity: quantity)
        trade.executeTrade()
        portfolio.addStock(stock: stock, quantity: quantity)
    }
    
    @IBAction func sellButtonTapped(_ sender: UIButton) {
        guard let stock = stockTextField.text, !stock.isEmpty else { return }
        guard let quantity = Int(quantityTextField.text ?? "") else { return }
        
        // Execute trade and update portfolio
        let trade = Trade(stock: stock, quantity: quantity)
        trade.executeTrade()
        portfolio.removeStock(stock: stock, quantity: quantity)
    }
    
    @IBAction func refreshButtonTapped(_ sender: UIButton) {
        // Refresh portfolio information
